export interface CSVOptions {
  delimiter?: string;
  quoteChar?: string;
  lineSeparator?: string;
}

export interface CSVError {
  row: number;
  message: string;
}

export interface CSVResult {
  rows: Array<Record<string, any>>;
  headers: string[];
  errors: CSVError[];
  filter(predicate: (row: Record<string, any>) => boolean): CSVResult;
  sum(column: string): number;
  average(column: string): number;
  count(): number;
  groupBy(column: string): Map<any, Array<Record<string, any>>>;
}

function coerceValue(value: string): any {
  const trimmed = value.trim();
  if (trimmed === "" || trimmed.toLowerCase() === "null") {
    return null;
  }
  const lower = trimmed.toLowerCase();
  if (lower === "true") return true;
  if (lower === "false") return false;
  if (/^-?\d+(\.\d+)?$/.test(trimmed)) {
    return Number(trimmed);
  }
  return value;
}

function splitLines(input: string, lineSeparator: string): string[] {
  if (lineSeparator === "\n") {
    return input.split(/\r?\n/);
  }
  return input.split(lineSeparator);
}

function parseCSVInternal(input: string, options: CSVOptions = {}): CSVResult {
  const delimiter = options.delimiter ?? ",";
  const quoteChar = options.quoteChar ?? "\"";
  const lineSeparator = options.lineSeparator ?? "\n";

  const rows: Array<Record<string, any>> = [];
  const errors: CSVError[] = [];

  if (!input.trim()) {
    return createResult(rows, [], errors, options);
  }

  const lines = splitLines(input, lineSeparator).filter((line, index, arr) => {
    if (index === arr.length - 1) {
      return line !== "";
    }
    return true;
  });

  if (lines.length === 0) {
    return createResult(rows, [], errors, options);
  }

  const headers = parseLine(lines[0], delimiter, quoteChar, errors, 1);

  for (let i = 1; i < lines.length; i += 1) {
    const line = lines[i];
    if (line === "") continue;
    const values = parseLine(line, delimiter, quoteChar, errors, i + 1);
    if (values.length !== headers.length) {
      errors.push({
        row: i + 1,
        message: `Malformed row: expected ${headers.length} fields, got ${values.length}`,
      });
      continue;
    }
    const row: Record<string, any> = {};
    for (let j = 0; j < headers.length; j += 1) {
      row[headers[j]] = coerceValue(values[j]);
    }
    rows.push(row);
  }

  return createResult(rows, headers, errors, options);
}

function parseLine(
  line: string,
  delimiter: string,
  quoteChar: string,
  errors: CSVError[],
  rowNumber: number
): string[] {
  const values: string[] = [];
  let current = "";
  let inQuotes = false;
  let i = 0;

  while (i < line.length) {
    const char = line[i];
    if (char === quoteChar) {
      if (inQuotes && line[i + 1] === quoteChar) {
        current += quoteChar;
        i += 2;
        continue;
      }
      inQuotes = !inQuotes;
      i += 1;
      continue;
    }

    if (char === delimiter && !inQuotes) {
      values.push(current);
      current = "";
      i += 1;
      continue;
    }

    current += char;
    i += 1;
  }

  if (inQuotes) {
    errors.push({ row: rowNumber, message: "Unclosed quoted field" });
  }

  values.push(current);
  return values;
}

function createResult(
  rows: Array<Record<string, any>>,
  headers: string[],
  errors: CSVError[],
  options: CSVOptions
): CSVResult {
  return {
    rows,
    headers,
    errors,
    filter(predicate: (row: Record<string, any>) => boolean): CSVResult {
      const filteredRows = rows.filter(predicate);
      return createResult(filteredRows, headers, errors, options);
    },
    sum(column: string): number {
      return rows.reduce((acc, row) => {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          return acc + value;
        }
        return acc;
      }, 0);
    },
    average(column: string): number {
      let total = 0;
      let count = 0;
      for (const row of rows) {
        const value = row[column];
        if (typeof value === "number" && !Number.isNaN(value)) {
          total += value;
          count += 1;
        }
      }
      return count === 0 ? 0 : total / count;
    },
    count(): number {
      return rows.length;
    },
    groupBy(column: string): Map<any, Array<Record<string, any>>> {
      const map = new Map<any, Array<Record<string, any>>>();
      for (const row of rows) {
        const key = row[column];
        if (!map.has(key)) {
          map.set(key, []);
        }
        map.get(key)!.push(row);
      }
      return map;
    },
  };
}

export function parseCSV(input: string, options?: CSVOptions): CSVResult {
  return parseCSVInternal(input, options);
}

import { parseCSV } from "./csv-parser";

function assert(condition: boolean, message: string) {
  if (!condition) {
    throw new Error(message);
  }
}

function assertEqual(actual: any, expected: any, message: string) {
  if (actual !== expected) {
    throw new Error(`${message}: expected ${expected}, got ${actual}`);
  }
}

function assertDeepEqual(actual: any, expected: any, message: string) {
  const actualJson = JSON.stringify(actual);
  const expectedJson = JSON.stringify(expected);
  if (actualJson !== expectedJson) {
    throw new Error(`${message}: expected ${expectedJson}, got ${actualJson}`);
  }
}

function runTests() {
  // Basic parsing
  const basic = parseCSV("name,age\nAlice,30\nBob,25");
  assertEqual(basic.headers.length, 2, "basic headers length");
  assertEqual(basic.rows.length, 2, "basic rows length");
  assertEqual(basic.rows[0].name, "Alice", "basic row name");
  assertEqual(basic.rows[0].age, 30, "basic row age");

  // Quoted fields with commas
  const quoted = parseCSV('name,quote\nAlice,"hello, world"');
  assertEqual(quoted.rows[0].quote, "hello, world", "quoted field with comma");

  // Escaped quotes
  const escaped = parseCSV('name,quote\nAlice,"She said ""hi"""');
  assertEqual(escaped.rows[0].quote, 'She said "hi"', "escaped quotes");

  // Custom delimiters
  const custom = parseCSV("name|age\nAlice|30", { delimiter: "|" });
  assertEqual(custom.rows[0].age, 30, "custom delimiter parsing");

  // Type coercion
  const types = parseCSV("num,bool,nullval,empty,text\n42,TRUE,NULL,,hello");
  assertEqual(types.rows[0].num, 42, "type coercion number");
  assertEqual(types.rows[0].bool, true, "type coercion boolean");
  assertEqual(types.rows[0].nullval, null, "type coercion null");
  assertEqual(types.rows[0].empty, null, "type coercion empty string to null");
  assertEqual(types.rows[0].text, "hello", "type coercion string");

  // Malformed row error collection
  const malformed = parseCSV("a,b\n1,2\n3");
  assertEqual(malformed.errors.length, 1, "malformed row error count");
  assertEqual(malformed.errors[0].row, 3, "malformed row error row");

  // Filter functionality
  const filtered = basic.filter((row) => row.age > 25);
  assertEqual(filtered.rows.length, 1, "filter count");
  assertEqual(filtered.rows[0].name, "Alice", "filter row match");

  // Aggregation methods
  const agg = parseCSV("name,score,group\nA,10,x\nB,20,x\nC,30,y");
  assertEqual(agg.sum("score"), 60, "sum aggregation");
  assertEqual(agg.average("score"), 20, "average aggregation");
  assertEqual(agg.count(), 3, "count aggregation");
  const grouped = agg.groupBy("group");
  assertEqual(grouped.get("x")!.length, 2, "groupBy aggregation group x");
  assertEqual(grouped.get("y")!.length, 1, "groupBy aggregation group y");

  // Edge cases: empty input
  const empty = parseCSV("");
  assertEqual(empty.rows.length, 0, "empty input rows");
  assertEqual(empty.headers.length, 0, "empty input headers");

  // Edge cases: single column
  const singleColumn = parseCSV("only\n1\n2");
  assertEqual(singleColumn.headers.length, 1, "single column header length");
  assertEqual(singleColumn.rows.length, 2, "single column row length");

  // Edge cases: single row
  const singleRow = parseCSV("a,b\n1,2");
  assertEqual(singleRow.rows.length, 1, "single row length");

  // Edge cases: very large fields
  const largeField = "a".repeat(10000);
  const large = parseCSV(`field\n${largeField}`);
  assertEqual(large.rows[0].field, largeField, "large field value");

  // Custom line separator
  const customLines = parseCSV("a;b|1;2|3;4", { delimiter: ";", lineSeparator: "|" });
  assertEqual(customLines.rows.length, 2, "custom line separator rows");
  assertEqual(customLines.rows[1].b, 4, "custom line separator value");
}

runTests();
console.log("All tests passed");

